import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  UserSearch,
  MapPin,
  Clock,
  Eye,
  Repeat,
  Smartphone,
  Monitor,
  Globe,
  ChevronDown,
  ChevronUp,
  ArrowRight,
  TrendingUp,
} from "lucide-react";
import { format, formatDistanceToNow } from "date-fns";
import { zhCN, enUS, pt } from "date-fns/locale";
import { startOfDay, subDays } from "date-fns";
import { fetchAllPaginated } from "@/lib/paginatedQuery";

interface VisitorDetail {
  visitor_id: string;
  visit_count: number;
  first_visit: string;
  last_visit: string;
  country: string | null;
  city: string | null;
  pages: Array<{ page_type: string; target_id: string | null; created_at: string }>;
  user_agent: string | null;
  referer: string | null;
  user_id: string | null;
  is_return: boolean;
  display_name: string | null;
}

const parseUserAgent = (ua: string | null): { device: string; icon: typeof Monitor } => {
  if (!ua) return { device: "未知", icon: Monitor };
  const isMobile = /mobile|android|iphone|ipad/i.test(ua);
  return {
    device: isMobile ? "移动端" : "桌面端",
    icon: isMobile ? Smartphone : Monitor,
  };
};

const pageTypeEmoji: Record<string, string> = {
  home: "🏠",
  restaurant: "🍽️",
  activity: "🎉",
  restaurants: "📋",
  activities: "📅",
  community: "💬",
  post: "📝",
  map: "🗺️",
  profile: "👤",
  auth: "🔐",
  "join-us": "🤝",
  shop: "🛒",
  recipe: "🧑‍🍳",
  membership: "💎",
  other: "📄",
};

interface Props {
  days: number;
}

const VisitorInsights = ({ days }: Props) => {
  const { i18n } = useTranslation();
  const [expandedVisitor, setExpandedVisitor] = useState<string | null>(null);
  const [visibleCount, setVisibleCount] = useState(20);

  const dateLocale = i18n.language === "zh" ? zhCN : i18n.language === "pt" ? pt : enUS;

  // Fetch historical visitor IDs for return visitor detection
  const { data: historicalVisitorDates } = useQuery({
    queryKey: ["historical-visitor-dates"],
    queryFn: async () => {
      // Fetch visitor_id + date pairs from the last 90 days for return detection
      const since = startOfDay(subDays(new Date(), 90)).toISOString();
      const views = await fetchAllPaginated(
        "page_views",
        "visitor_id,created_at",
        (query) => query.gte("created_at", since)
      );
      // Build a map: visitor_id -> Set of unique dates
      const map = new Map<string, Set<string>>();
      views.forEach((v: any) => {
        const date = v.created_at.split("T")[0];
        if (!map.has(v.visitor_id)) map.set(v.visitor_id, new Set());
        map.get(v.visitor_id)!.add(date);
      });
      return map;
    },
    staleTime: 5 * 60 * 1000,
  });

  const { data: visitors, isLoading } = useQuery({
    queryKey: ["visitor-insights", days],
    queryFn: async (): Promise<VisitorDetail[]> => {
      let dateFilter: string | null = null;
      let dateFilterEnd: string | null = null;
      
      if (days === -1) {
        const yesterday = subDays(new Date(), 1);
        dateFilter = startOfDay(yesterday).toISOString();
        dateFilterEnd = startOfDay(new Date()).toISOString();
      } else if (days === 1) {
        dateFilter = startOfDay(new Date()).toISOString();
      } else if (days > 1) {
        dateFilter = startOfDay(subDays(new Date(), days - 1)).toISOString();
      }

      const views = await fetchAllPaginated(
        "page_views",
        "visitor_id,page_type,target_id,created_at,user_agent,referer,country,city,user_id",
        (query) => {
          if (dateFilter) query = query.gte("created_at", dateFilter);
          if (dateFilterEnd) query = query.lt("created_at", dateFilterEnd);
          return query.order("created_at", { ascending: false });
        }
      );

      // Collect unique user_ids for profile lookup
      const userIds = new Set<string>();
      views.forEach((v: any) => { if (v.user_id) userIds.add(v.user_id); });
      
      // Fetch display names for registered users
      let profileMap = new Map<string, string>();
      if (userIds.size > 0) {
        const { data: profiles } = await supabase
          .from("profiles")
          .select("id, display_name")
          .in("id", Array.from(userIds));
        if (profiles) {
          profiles.forEach((p) => {
            if (p.display_name) profileMap.set(p.id, p.display_name);
          });
        }
      }

      // Group by visitor_id
      const visitorMap = new Map<string, VisitorDetail>();

      views.forEach((v: any) => {
        if (!visitorMap.has(v.visitor_id)) {
          visitorMap.set(v.visitor_id, {
            visitor_id: v.visitor_id,
            visit_count: 0,
            first_visit: v.created_at,
            last_visit: v.created_at,
            country: v.country,
            city: v.city,
            pages: [],
            user_agent: v.user_agent,
            referer: v.referer,
            user_id: v.user_id,
            is_return: false,
            display_name: null,
          });
        }
        const visitor = visitorMap.get(v.visitor_id)!;
        visitor.visit_count++;
        visitor.pages.push({
          page_type: v.page_type,
          target_id: v.target_id,
          created_at: v.created_at,
        });
        if (v.created_at < visitor.first_visit) visitor.first_visit = v.created_at;
        if (v.created_at > visitor.last_visit) visitor.last_visit = v.created_at;
        if (v.user_id) {
          visitor.user_id = v.user_id;
          visitor.display_name = profileMap.get(v.user_id) || null;
        }
      });

      // Sort pages by time ascending
      visitorMap.forEach((visitor) => {
        visitor.pages.sort((a, b) => a.created_at.localeCompare(b.created_at));
      });

      // Sort by visit count descending
      return Array.from(visitorMap.values()).sort(
        (a, b) => b.visit_count - a.visit_count
      );
    },
  });

  // Mark return visitors using historical data (visited on multiple different dates across 90 days)
  const enrichedVisitors = useMemo(() => {
    if (!visitors) return [];
    return visitors.map((v) => ({
      ...v,
      is_return: historicalVisitorDates?.get(v.visitor_id)?.size
        ? historicalVisitorDates.get(v.visitor_id)!.size > 1
        : false,
    }));
  }, [visitors, historicalVisitorDates]);

  // Top visited page types
  const pageTypeCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    enrichedVisitors.forEach((v) => {
      v.pages.forEach((p) => {
        counts[p.page_type] = (counts[p.page_type] || 0) + 1;
      });
    });
    return Object.entries(counts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);
  }, [enrichedVisitors]);

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <Skeleton className="h-6 w-48" />
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {[...Array(5)].map((_, i) => (
              <Skeleton key={i} className="h-16" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  const totalVisitors = enrichedVisitors.length;
  const returnVisitors = enrichedVisitors.filter((v) => v.is_return).length;
  const mobileVisitors = enrichedVisitors.filter((v) => /mobile|android|iphone|ipad/i.test(v.user_agent || "")).length;
  const registeredVisitors = enrichedVisitors.filter((v) => v.user_id).length;
  const totalPageViews = enrichedVisitors.reduce((sum, v) => sum + v.visit_count, 0);
  const displayVisitors = enrichedVisitors.slice(0, visibleCount);

  return (
    <div className="space-y-6">
      {/* Summary row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <UserSearch className="w-4 h-4" />
              独立访客
            </div>
            <div className="text-2xl font-bold">{totalVisitors}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Repeat className="w-4 h-4" />
              回头访客
            </div>
            <div className="text-2xl font-bold">
              {returnVisitors}
              <span className="text-sm font-normal text-muted-foreground ml-1">
                ({totalVisitors > 0 ? ((returnVisitors / totalVisitors) * 100).toFixed(0) : 0}%)
              </span>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Smartphone className="w-4 h-4" />
              移动端访客
            </div>
            <div className="text-2xl font-bold">
              {mobileVisitors}
              <span className="text-sm font-normal text-muted-foreground ml-1">
                ({totalVisitors > 0 ? ((mobileVisitors / totalVisitors) * 100).toFixed(0) : 0}%)
              </span>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Eye className="w-4 h-4" />
              人均浏览
            </div>
            <div className="text-2xl font-bold">
              {totalVisitors > 0 ? (totalPageViews / totalVisitors).toFixed(1) : 0}
              <span className="text-sm font-normal text-muted-foreground ml-1">页</span>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Quick stats row */}
      <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <UserSearch className="w-4 h-4" />
              已注册用户
            </div>
            <div className="text-2xl font-bold">
              {registeredVisitors}
              <span className="text-sm font-normal text-muted-foreground ml-1">
                ({totalVisitors > 0 ? ((registeredVisitors / totalVisitors) * 100).toFixed(0) : 0}%)
              </span>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Eye className="w-4 h-4" />
              总浏览量
            </div>
            <div className="text-2xl font-bold">{totalPageViews}</div>
          </CardContent>
        </Card>
        <Card className="col-span-2 md:col-span-1">
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-2">
              <TrendingUp className="w-4 h-4" />
              热门页面
            </div>
            <div className="flex flex-wrap gap-1">
              {pageTypeCounts.map(([type, count]) => (
                <Badge key={type} variant="secondary" className="text-xs">
                  {pageTypeEmoji[type] || "📄"} {type} ({count})
                </Badge>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Visitor List */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <UserSearch className="w-5 h-5" />
            访客详情（谁在关注你）
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div>
            <div className="space-y-2">
              {displayVisitors.map((visitor, index) => {
                const { device, icon: DeviceIcon } = parseUserAgent(visitor.user_agent);
                const isExpanded = expandedVisitor === visitor.visitor_id;

                return (
                  <div
                    key={visitor.visitor_id}
                    className="border rounded-lg overflow-hidden"
                  >
                    <button
                      className="w-full flex items-center justify-between p-3 hover:bg-muted/50 transition-colors text-left"
                      onClick={() =>
                        setExpandedVisitor(isExpanded ? null : visitor.visitor_id)
                      }
                    >
                      <div className="flex items-center gap-3 min-w-0">
                        <Badge
                          variant={index < 3 ? "default" : "secondary"}
                          className="w-6 h-6 p-0 justify-center shrink-0"
                        >
                          {index + 1}
                        </Badge>
                        <div className="min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            {visitor.display_name ? (
                              <span className="font-medium text-sm truncate max-w-[160px]">
                                {visitor.display_name}
                              </span>
                            ) : (visitor.country || visitor.city) ? (
                              <span className="font-medium text-sm">
                                {[visitor.city, visitor.country].filter(Boolean).join(", ")} 访客
                              </span>
                            ) : (
                              <span className="font-mono text-xs text-muted-foreground">
                                匿名访客 #{visitor.visitor_id.slice(0, 6)}
                              </span>
                            )}
                            {visitor.user_id && (
                              <Badge variant="outline" className="text-xs bg-blue-50 dark:bg-blue-950 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-800">
                                已注册
                              </Badge>
                            )}
                            {visitor.is_return && (
                              <Badge variant="outline" className="text-xs bg-amber-50 dark:bg-amber-950 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-800">
                                <Repeat className="w-3 h-3 mr-1" />
                                回头客
                              </Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-3 mt-1 text-xs text-muted-foreground">
                            {(visitor.country || visitor.city) && visitor.display_name && (
                              <span className="flex items-center gap-1">
                                <MapPin className="w-3 h-3" />
                                {[visitor.city, visitor.country].filter(Boolean).join(", ")}
                              </span>
                            )}
                            <span className="flex items-center gap-1">
                              <DeviceIcon className="w-3 h-3" />
                              {device}
                            </span>
                            <span className="text-muted-foreground">
                              {(() => {
                                const uniqueTypes = [...new Set(visitor.pages.map(p => p.page_type))];
                                return uniqueTypes.slice(0, 3).map(t => pageTypeEmoji[t] || "📄").join(" ");
                              })()}
                            </span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-3 shrink-0">
                        <div className="text-right">
                          <div className="text-sm font-medium">{visitor.visit_count} 次浏览</div>
                          <div className="text-xs text-muted-foreground">
                            {formatDistanceToNow(new Date(visitor.last_visit), {
                              addSuffix: true,
                              locale: dateLocale,
                            })}
                          </div>
                        </div>
                        {isExpanded ? (
                          <ChevronUp className="w-4 h-4 text-muted-foreground" />
                        ) : (
                          <ChevronDown className="w-4 h-4 text-muted-foreground" />
                        )}
                      </div>
                    </button>

                    {isExpanded && (
                      <div className="border-t bg-muted/30 p-3">
                        <div className="text-xs text-muted-foreground mb-2">浏览路径：</div>
                        <div className="flex flex-wrap items-center gap-1">
                          {visitor.pages.slice(0, 20).map((page, pi) => (
                            <span key={pi} className="flex items-center gap-0.5">
                              {pi > 0 && (
                                <ArrowRight className="w-3 h-3 text-muted-foreground mx-0.5" />
                              )}
                              <Badge variant="outline" className="text-xs font-normal">
                                {pageTypeEmoji[page.page_type] || "📄"}{" "}
                                {page.page_type}
                                <span className="text-muted-foreground ml-1">
                                  {format(new Date(page.created_at), "HH:mm")}
                                </span>
                              </Badge>
                            </span>
                          ))}
                          {visitor.pages.length > 20 && (
                            <span className="text-xs text-muted-foreground">
                              …还有 {visitor.pages.length - 20} 条
                            </span>
                          )}
                        </div>
                        {visitor.referer && (
                          <div className="mt-2 text-xs text-muted-foreground">
                            <Globe className="w-3 h-3 inline mr-1" />
                            来源: {visitor.referer}
                          </div>
                        )}
                        <div className="mt-2 text-xs text-muted-foreground">
                          <Clock className="w-3 h-3 inline mr-1" />
                          首次访问: {format(new Date(visitor.first_visit), "yyyy-MM-dd HH:mm")}
                          {visitor.first_visit !== visitor.last_visit && (
                            <> → 最近: {format(new Date(visitor.last_visit), "yyyy-MM-dd HH:mm")}</>
                          )}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}

              {totalVisitors === 0 && (
                <div className="text-center py-8 text-muted-foreground">
                  暂无访客数据
                </div>
              )}
            </div>
          </div>

          {totalVisitors > visibleCount && (
            <div className="mt-4 text-center">
              <Button variant="outline" size="sm" onClick={() => setVisibleCount((prev) => prev + 50)}>
                加载更多（已显示 {visibleCount}/{totalVisitors}）
              </Button>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default VisitorInsights;
